UPDATE violation_record
driver_id = #{driverId}, vehicle_id = #{vehicleId}, line_id = #{lineId}, station_id = #{stationId}, violation_type_id = #{violationTypeId}, violation_time = #{violationTime}, description = #{description}, inputter_id = #{inputterId},
WHERE record_id = #{recordId}

mapper.select:
SELECT * FROM driver_violation_view


        AND (driver_name LIKE CONCAT('%', #{keyword}, '%')
             OR license_plate LIKE CONCAT('%', #{keyword}, '%'))


        AND fleet_id = #{fleetId}


        AND line_id = #{lineId}


        AND violation_type_id = #{violationTypeId}


        AND station_id = #{stationId}


        AND violation_time >= #{startTime}


        AND violation_time <= #{endTime}


ORDER BY violation_time DESC

SELECT f.fleet_name AS name, COUNT(*) AS total_count, SUM(CASE WHEN vt.type_name = '闯红灯' THEN 1 ELSE 0 END) AS red_light, SUM(CASE WHEN vt.type_name = '压线' THEN 1 ELSE 0 END) AS line_crossing, SUM(CASE WHEN vt.type_name = '未礼让斑马线' THEN 1 ELSE 0 END) AS no_yield, SUM(CASE WHEN vt.type_name = '违章停车' THEN 1 ELSE 0 END) AS illegal_parking, SUM(CASE WHEN vt.type_name = '超速' THEN 1 ELSE 0 END) AS speeding FROM violation_record v JOIN line l ON v.line_id = l.line_id JOIN fleet f ON l.fleet_id = f.fleet_id JOIN violation_type vt ON v.violation_type_id = vt.type_id
AND v.violation_time >= #{startTime}
AND v.violation_time <= #{endTime}
GROUP BY f.fleet_id, f.fleet_name

SELECT l.line_name AS name, COUNT(*) AS total_count, SUM(CASE WHEN vt.type_name = '闯红灯' THEN 1 ELSE 0 END) AS red_light, SUM(CASE WHEN vt.type_name = '压线' THEN 1 ELSE 0 END) AS line_crossing, SUM(CASE WHEN vt.type_name = '未礼让斑马线' THEN 1 ELSE 0 END) AS no_yield, SUM(CASE WHEN vt.type_name = '违章停车' THEN 1 ELSE 0 END) AS illegal_parking, SUM(CASE WHEN vt.type_name = '超速' THEN 1 ELSE 0 END) AS speeding FROM violation_record v JOIN line l ON v.line_id = l.line_id JOIN violation_type vt ON v.violation_type_id = vt.type_id
AND v.violation_time >= #{startTime}
AND v.violation_time <= #{endTime}
GROUP BY l.line_id, l.line_name

SELECT vt.type_name AS name, COUNT(*) AS total_count FROM violation_record v JOIN violation_type vt ON v.violation_type_id = vt.type_id
AND v.violation_time >= #{startTime}
AND v.violation_time <= #{endTime}
GROUP BY vt.type_id, vt.type_name

SELECT DATE_FORMAT(v.violation_time, '%Y-%m') AS month, COUNT(*) AS count FROM violation_record v
AND v.violation_time >= #{startTime}
AND v.violation_time <= #{endTime}
GROUP BY DATE_FORMAT(v.violation_time, '%Y-%m') ORDER BY month
